@Finset.Nat.sum_antidiagonal_swap : ∀ {M : Type u_1} [inst : AddCommMonoid M] {n : ℕ} {f : ℕ × ℕ → M},
  ∑ p ∈ Finset.antidiagonal n, f p.swap = ∑ p ∈ Finset.antidiagonal n, f p

